import UIKit

// Define a class to handle universal links
class LinkHandler {
    // Implement the AppDelegate protocol to receive universal link events
    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        // Extract URL components
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else { return false }
        
        // Extract token from URL query parameters
        var token: String?
        for key in components.queryParameters.keys where key == "token" {
            token = components.queryParameters[key]!
        }
        
        // Navigate to password reset screen if token is present
        if let token = token, !token.isEmpty {
            self.navigateToPasswordResetScreen(token)
            return true
        }
        
        // Return false if no valid token was extracted
        return false
    }
    
    private func navigateToPasswordResetScreen(_ token: String) {
        // Navigate to the password reset screen with the extracted token
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let vc = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController")
        
        // Pass the token as a parameter to the password reset view controller
        vc.token = token
        
        // Present the view controller
        (UIApplication.shared.delegate as? AppDelegate)?.window?.rootViewController?.present(vc, animated: true, completion: nil)
    }
}

